var f = this, g1 = f.getItem('hrttctxh')._controlBehavior, g2 = f.getItem('hrttctyt')._controlBehavior, g3 = f.getItem('hrttcttn')._controlBehavior, g4 = f.getItem('hrttctcd')._controlBehavior, g5 = f.getItem('hrttctdtbh')._controlBehavior;
if (f._checked) {
	check$InsuranceForm$DataGrid(f, g1, 'hrttctxh', 'ngay_hl_tu', 'ngay_hl_den', null);
	check$InsuranceForm$DataGrid(f, g2, 'hrttctyt', 'ngay_hl_tu', 'ngay_hl_den', null);
	check$InsuranceForm$DataGrid(f, g3, 'hrttcttn', 'ngay_hl_tu', 'ngay_hl_den', null);
	check$InsuranceForm$DataGrid(f, g4, 'hrttctcd', 'ngay_hl_tu', 'ngay_hl_den', null);
  check$InsuranceForm$DataGrid(f, g5, 'hrttctdtbh', 'ngay_hl_tu', 'ngay_hl_den', null);
}

script.text:

function load$EmployeeInsuranceAndUnionDueInformation(f) {
  var l = f._language == 'v' ? '' : '2';
  f.setReadOnlyFields('ma_nv, bo_phan, vi_tri, ho_ten, ten_bp' + l + ', ten_vtr' + l + ', ten_bac_ql' + l + ', ngay_vao, ngay_nghi, ngay_sinh, ten_qt' + l + ', cmnd_so, cmnd_ngay_hl, cmnd_noi_cap, ten_tinh' + l + ', cmnd_ngay_hh');
  f.getItem('si_no').maxLength = parseInt(f._externalLength[0]);
  f.getItem('hi_no').maxLength = parseInt(f._externalLength[1]);
  f.getItem('quyen_loi').maxLength = parseInt(f._externalLength[2]);
  f.getItem('ma_so_bhxh').maxLength = parseInt(f._externalLength[3]);
  f.getItem('ma_so_hgd').maxLength = parseInt(f._externalLength[4]);
  f.getItem('ma_so_bhxh').focus();

  f.add_commandEvent(on$EmployeeInsuranceAndUnionDueInformation$ExecuteCommand);
  f._tabContainer.add_activeTabChanged(onChange$Voucher$Tab);
  f._tabContainer._loaded = true;
}
function onChange$Voucher$Tab(sender, e) {sender.parentForm.focusWhenTabChanged(['ma_so_bhxh', 'hrttctxh', 'hrttctyt', 'hrttcttn', 'hrttctcd', 'hrttctdtbh', 'hrhgd']);}
function close$EmployeeInsuranceAndUnionDueInformation(f) {
  try {f.remove_commandEvent(on$EmployeeInsuranceAndUnionDueInformation$ExecuteCommand);} catch (ex) {}
  if (f._tabContainer) try {f._tabContainer.remove_activeTabChanged(onChange$Voucher$Tab);} catch (ex) {}
}
function on$EmployeeInsuranceAndUnionDueInformation$ExecuteCommand(sender, e) {
  var action = e.type.Action, f = sender, g1 = f.getItem('hrttctxh')._controlBehavior, g2 = f.getItem('hrttctyt')._controlBehavior, g3 = f.getItem('hrttcttn')._controlBehavior, g4 = f.getItem('hrttctcd')._controlBehavior, g6 = f.getItem('hrttctdtbh')._controlBehavior, g5 = f.getItem('hrhgd')._controlBehavior;
  switch (action) {
    case 'Gather':
      g1.setSequenceNumber('line_nbr');
      g1.setContinuance('stt_rec0');
      g2.setSequenceNumber('line_nbr');
      g2.setContinuance('stt_rec0');
      g3.setSequenceNumber('line_nbr');
      g3.setContinuance('stt_rec0');
      g4.setSequenceNumber('line_nbr');
      g4.setContinuance('stt_rec0');
      g5.setSequenceNumber('line_nbr');
      g5.setContinuance('stt_rec0');
      g6.setSequenceNumber('line_nbr');
      g6.setContinuance('stt_rec0');
      break;
    default:
      break;
  }
}
function set$ExternalMaxLengthFields(f, s) {
  var a = s.split(',');
  f._externalLength = a;
}
function check$InsuranceForm$DataGrid(f, g, d, s1, s2, s3) {
  var id = f.get_id(), gID = g.get_id(), v = f._language == 'v';
  var e1 = (v ? 'Trường <span class="Highlight">Hiệu lực từ ngày</span> phải nhỏ hơn trường <span class="Highlight">Đến ngày</span>.' : '<span class="Highlight">Effective from</span> must be less than <span class="Highlight">Effective to</span>.');
  var e2 = (v ? 'Trường <span class="Highlight">Hiệu lực đến ngày</span> chưa nhập hoặc giá trị không hợp lệ.' : 'Field <span class="Highlight">Effective to</span> must not be blank or has invalid value.');
  var e3 = (v ? 'Trường <span class="Highlight">Hiệu lực từ ngày</span> chưa nhập hoặc giá trị không hợp lệ.' : 'Field <span class="Highlight">Effective from</span> must not be blank or has invalid value.');

  var t1 = g._getColumnOrder(s1), t2 = g._getColumnOrder(s2);
  for (var i = 1; i <= g._rowCount; i++) {
    var d1 = g._getItemValue(i, t1), d2 = g._getItemValue(i, t2);
    if (d2 != null) {
      if (d1 > d2) {
        g._errorWarningObject = g._getItem(i, t2);
        $func.hideWait(id);
        $message.show(e1, String.format('$find(\'{0}\').focus(\'{1}\');$find(\'{2}\')._errorWarningObject.focus()', id, d, gID));
        f._checked = false;
        break;
      }
    }

    if (f._checked && i < g._rowCount) {
      var n = i;
      if (s3 != null) {
        var k = g._getColumnOrder(s3), c = g._getItemValue(i, k);
        for (var j = i + 1; i <= g._rowCount; i++) {
          if (g._getItemValue(j, k) == c) {n = j; break;}
        }
      } else n += 1;

      if (n > i && !d2) {
        g._errorWarningObject = g._getItem(i, t2);
        $func.hideWait(id);
        $message.show(e2, String.format('$find(\'{0}\').focus(\'{1}\');$find(\'{2}\')._errorWarningObject.focus()', id, d, gID));
        f._checked = false;
        break;
      }

      if (f._checked && n > i) {
        var d3 = g._getItemValue(n, t1);
        if (d2 >= d3) {
          g._errorWarningObject = g._getItem(n, t1);
          $func.hideWait(id);
          $message.show(e3, String.format('$find(\'{0}\').focus(\'{1}\');$find(\'{2}\')._errorWarningObject.focus()', id, d, gID));
          f._checked = false;
          break;
        }
      }
    }
  }
}
